@* Step progress indicator *@

<nav class="mb-4" aria-label="Application steps">
    <div class="d-flex justify-content-between position-relative step-indicator">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="text-center step-item @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                 style="flex: 1; cursor: @(isCompleted ? "pointer" : "default");"
                 @onclick="() => HandleStepClick(step)"
                 role="@(isCompleted ? "button" : "")"
                 aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <small class="d-none d-md-block @(isFuture ? "text-muted" : "") @(isCurrent ? "fw-bold text-primary" : "")">
                    @StepNames[step]
                </small>
            </div>
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = default!;
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

