arguments.file_text:
@page "/apply"
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep;
    private int? submittedApplicationId;

    private readonly List<string> stepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    // Form state owned by this page, shared across steps
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, stepNames.Count - 1);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = Math.Clamp(step, 0, stepNames.Count - 1);
    private void HandleSubmitted(int id) => submittedApplicationId = id;
}

::deep .step-indicator .step-item.completed:hover .step-circle {
    opacity: 0.85;
}

::deep .step-indicator .step-item.future {
    opacity: 0.5;
}

::deep .last-no-border:last-child {
    border-bottom: none !important;
    margin-bottom: 0 !important;
    padding-bottom: 0 !important;
}

@page "/apply"
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
